import{_ as l,o as e,c as r,ai as i}from"./chunks/framework.BOVdWEjA.js";const b=JSON.parse('{"title":"更新日志","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),t={name:"changelog.md"};function o(h,a,n,s,d,c){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="更新日志" tabindex="-1">更新日志 <a class="header-anchor" href="#更新日志" aria-label="Permalink to “更新日志”">​</a></h1><p>记录服务器的重要更新和玩法调整。</p><hr><h2 id="_2026-04-05" tabindex="-1">2026-04-05 <a class="header-anchor" href="#_2026-04-05" aria-label="Permalink to “2026-04-05”">​</a></h2><h3 id="战利品调整" tabindex="-1">战利品调整 <a class="header-anchor" href="#战利品调整" aria-label="Permalink to “战利品调整”">​</a></h3><ul><li>因 <strong>回忆药水</strong> 所需酿造材料为回响碎片，所以将回响碎片添加至 <strong>监守者</strong> 的战利品列表中; <ul><li>数量为0-1，掉落几率90%</li></ul></li></ul><h2 id="_2026-04-05-1" tabindex="-1">2026-04-05 <a class="header-anchor" href="#_2026-04-05-1" aria-label="Permalink to “2026-04-05”">​</a></h2><h3 id="服务器版本更新-维度更新" tabindex="-1">服务器版本更新&amp;维度更新 <a class="header-anchor" href="#服务器版本更新-维度更新" aria-label="Permalink to “服务器版本更新&amp;维度更新”">​</a></h3><ul><li>已将服务器版本升至 26.1.1</li><li>增加了天堂(空岛) <ul><li>空岛只会刷新在700格的位置</li></ul></li><li>由于版本升级导致以下模组暂时停止支持，将在未来更新后继续提供支持(目前不影响客户端使用，只是不提供服务器数据)： <ul><li><a href="https://modrinth.com/mod/jade" target="_blank" rel="noreferrer">Jade</a></li><li><a href="https://modrinth.com/mod/appleskin" target="_blank" rel="noreferrer">AppleSkin</a></li><li><a href="https://modrinth.com/mod/asteorbar" target="_blank" rel="noreferrer">AsteorBar</a></li><li><a href="https://modrinth.com/mod/chatimage" target="_blank" rel="noreferrer">ChatImage</a></li><li><a href="https://modrinth.com/mod/xaeros-minimap" target="_blank" rel="noreferrer">XaeroMap</a></li><li><a href="https://modrinth.com/mod/do-a-barrel-roll" target="_blank" rel="noreferrer">Do a Barrel Roll</a></li><li><a href="https://modrinth.com/mod/jei" target="_blank" rel="noreferrer">JEI</a></li></ul></li><li>由于版本原因暂时停止了以下内容： <ul><li>椅子</li><li>玩家骑乘</li><li>@ 玩家</li><li>VR 支持</li></ul></li><li>临时暂停了以下物品的使用, 将在短期内恢复: <ul><li><strong>守护药剂</strong></li></ul></li></ul><h2 id="_2026-03-20" tabindex="-1">2026-03-20 <a class="header-anchor" href="#_2026-03-20" aria-label="Permalink to “2026-03-20”">​</a></h2><h3 id="服务器增加兼容性" tabindex="-1">服务器增加兼容性 <a class="header-anchor" href="#服务器增加兼容性" aria-label="Permalink to “服务器增加兼容性”">​</a></h3><ul><li>本次更新为以下mod的增加了来自服务端的兼容性： <ul><li><a href="https://modrinth.com/mod/jade" target="_blank" rel="noreferrer">Jade</a></li><li><a href="https://modrinth.com/mod/appleskin" target="_blank" rel="noreferrer">AppleSkin</a></li><li><a href="https://modrinth.com/mod/asteorbar" target="_blank" rel="noreferrer">AsteorBar</a></li><li><a href="https://modrinth.com/mod/chatimage" target="_blank" rel="noreferrer">ChatImage</a></li><li><a href="https://modrinth.com/mod/xaeros-minimap" target="_blank" rel="noreferrer">XaeroMap</a></li><li><a href="https://modrinth.com/mod/do-a-barrel-roll" target="_blank" rel="noreferrer">Do a Barrel Roll</a></li></ul></li></ul><h2 id="_2026-03-18" tabindex="-1">2026-03-18 <a class="header-anchor" href="#_2026-03-18" aria-label="Permalink to “2026-03-18”">​</a></h2><h3 id="新增服务器功能" tabindex="-1">新增服务器功能 <a class="header-anchor" href="#新增服务器功能" aria-label="Permalink to “新增服务器功能”">​</a></h3><ul><li>为服务器开发了新的插件(<a href="#">homePotion</a>) <ul><li>用于回到复活点</li></ul></li><li>新增酿造配方： <strong>回忆药水</strong></li></ul><h2 id="_2026-03-18-1" tabindex="-1">2026-03-18 <a class="header-anchor" href="#_2026-03-18-1" aria-label="Permalink to “2026-03-18”">​</a></h2><h3 id="新增服务器功能-1" tabindex="-1">新增服务器功能 <a class="header-anchor" href="#新增服务器功能-1" aria-label="Permalink to “新增服务器功能”">​</a></h3><ul><li>为服务器开发了新的插件(<a href="https://github.com/User-Time/EnderPocket" target="_blank" rel="noreferrer">EnderPocket</a>) <ul><li>使玩家手持末影箱打开</li></ul></li></ul><h2 id="_2026-03-16" tabindex="-1">2026-03-16 <a class="header-anchor" href="#_2026-03-16" aria-label="Permalink to “2026-03-16”">​</a></h2><h3 id="新增服务器功能-2" tabindex="-1">新增服务器功能 <a class="header-anchor" href="#新增服务器功能-2" aria-label="Permalink to “新增服务器功能”">​</a></h3><ul><li>为代理服务器开发了新的插件(<a href="https://hangar.papermc.io/Time/MultiProxySync" target="_blank" rel="noreferrer">MultiProxySync</a>) <ul><li>使多个服务器的Ping返回的玩家数量保持一致</li></ul></li></ul><h2 id="_2026-03-15" tabindex="-1">2026-03-15 <a class="header-anchor" href="#_2026-03-15" aria-label="Permalink to “2026-03-15”">​</a></h2><h3 id="更改网络结构" tabindex="-1">更改网络结构 <a class="header-anchor" href="#更改网络结构" aria-label="Permalink to “更改网络结构”">​</a></h3><ul><li>移除了 GA 网络优化</li><li>保持了 北美线路 优化</li></ul><h2 id="_2026-03-13" tabindex="-1">2026-03-13 <a class="header-anchor" href="#_2026-03-13" aria-label="Permalink to “2026-03-13”">​</a></h2><h3 id="优化网络结构" tabindex="-1">优化网络结构 <a class="header-anchor" href="#优化网络结构" aria-label="Permalink to “优化网络结构”">​</a></h3><ul><li>为服务器增加多条<strong>加速线路</strong>： <ul><li><strong>北京</strong>、<strong>杭州</strong>、<strong>广州</strong>、<strong>硅谷</strong>(美国)</li><li>为以上所有节点配置了 <strong>BGP</strong> 线路优化</li></ul></li><li><strong>JAVA版</strong>服务器入口 与 <strong>基岩版</strong>服务器入口 正式完成互通</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>目前优化线路暂只提供 <strong>Java版在线</strong> 入口进行测试</p></div><h2 id="_2026-03-12" tabindex="-1">2026-03-12 <a class="header-anchor" href="#_2026-03-12" aria-label="Permalink to “2026-03-12”">​</a></h2><h3 id="新增功能-新增成就-新增配方" tabindex="-1">新增功能&amp;新增成就&amp;新增配方 <a class="header-anchor" href="#新增功能-新增成就-新增配方" aria-label="Permalink to “新增功能&amp;新增成就&amp;新增配方”">​</a></h3><ul><li>LimitedGrace插件更新，可以获得额外死亡不掉落机会</li><li>新增两个 <strong>死亡不掉落</strong> 相关成就</li><li>新增合成配方： <strong>守护药剂</strong></li></ul><h2 id="_2026-03-11" tabindex="-1">2026-03-11 <a class="header-anchor" href="#_2026-03-11" aria-label="Permalink to “2026-03-11”">​</a></h2><h3 id="新增功能-更改难度" tabindex="-1">新增功能&amp;更改难度 <a class="header-anchor" href="#新增功能-更改难度" aria-label="Permalink to “新增功能&amp;更改难度”">​</a></h3><ul><li>为服务器开发了新的插件 <em>(<a href="https://github.com/User-Time/LimitedGrace" target="_blank" rel="noreferrer">LimitedGrace</a>)</em></li><li>目前服务器内 <strong>前10次</strong> 死亡将会受到死亡保护</li><li>服务器难度 正式更改为 <strong>困难</strong> 模式</li></ul><h2 id="_2026-02-28" tabindex="-1">2026-02-28 <a class="header-anchor" href="#_2026-02-28" aria-label="Permalink to “2026-02-28”">​</a></h2><h3 id="新增配方-服务器优化" tabindex="-1">新增配方&amp;服务器优化 <a class="header-anchor" href="#新增配方-服务器优化" aria-label="Permalink to “新增配方&amp;服务器优化”">​</a></h3><ul><li>已增加 透明装备 的合成配方</li><li>优化了 服务器 所在的物理网络环境</li></ul><h2 id="_2026-02-28-1" tabindex="-1">2026-02-28 <a class="header-anchor" href="#_2026-02-28-1" aria-label="Permalink to “2026-02-28”">​</a></h2><h3 id="优化服务器兼容性" tabindex="-1">优化服务器兼容性 <a class="header-anchor" href="#优化服务器兼容性" aria-label="Permalink to “优化服务器兼容性”">​</a></h3><ul><li>已兼容 JEI 查看合成配方</li><li>已支持 Distant Horizon</li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>因1.21.2开始服务端默认不再向客户端发送完整配方数据。 而 JEI 是客户端模组，它需要从服务器获取配方数据才能正确显示合成配方。</p></div><h2 id="_2026-02-27" tabindex="-1">2026-02-27 <a class="header-anchor" href="#_2026-02-27" aria-label="Permalink to “2026-02-27”">​</a></h2><h3 id="添加合成配方" tabindex="-1">添加合成配方 <a class="header-anchor" href="#添加合成配方" aria-label="Permalink to “添加合成配方”">​</a></h3><ul><li>新增 鞘翅胸甲 合成配方</li><li>增加 “命令方块” 配方</li></ul><h2 id="_2026-02-24" tabindex="-1">2026-02-24 <a class="header-anchor" href="#_2026-02-24" aria-label="Permalink to “2026-02-24”">​</a></h2><h3 id="添加服务器支持-服务器地址变更" tabindex="-1">添加服务器支持&amp;服务器地址变更 <a class="header-anchor" href="#添加服务器支持-服务器地址变更" aria-label="Permalink to “添加服务器支持&amp;服务器地址变更”">​</a></h3><ul><li>服务器地址迁移为 Minecraft.Potg.org</li><li>服务器已增加vivecraft，来对VR用户提供支持。</li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>vivecraft 是一款客户端/服务端模组，可将 Minecraft 增加卓越 VR 体验。</p></div><h2 id="_2026-02-23" tabindex="-1">2026-02-23 <a class="header-anchor" href="#_2026-02-23" aria-label="Permalink to “2026-02-23”">​</a></h2><h3 id="新增玩法" tabindex="-1">新增玩法 <a class="header-anchor" href="#新增玩法" aria-label="Permalink to “新增玩法”">​</a></h3><ul><li>已新增表情包功能</li></ul><h2 id="_2026-02-20" tabindex="-1">2026-02-20 <a class="header-anchor" href="#_2026-02-20" aria-label="Permalink to “2026-02-20”">​</a></h2><h3 id="服务器重新成立" tabindex="-1">服务器重新成立 <a class="header-anchor" href="#服务器重新成立" aria-label="Permalink to “服务器重新成立”">​</a></h3><ul><li>受 Acovia 与 CMFS 服务器影响，服务器已重新成立，并开启正版验证。</li><li>版本选择为 1.21.11 使用了双velocity+leaf+paper的组成，实现了正版入口+离线入口使得离线玩家也可以加入服务器一起玩耍。</li><li>服务器已支持ipv4和ipv6双协议，以照顾不同网络环境玩家</li></ul><hr>',55)])])}const f=l(t,[["render",o]]);export{b as __pageData,f as default};
